        {/* Sources */}
        {result.sources && result.sources.length > 0 && (
          <div className="mt-24 pt-10 border-t border-slate-200">
            <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-8">
              Verification Footprints
