                    <h3 className="text-sm font-bold text-red-900 uppercase tracking-wider">Something went wrong</h3>
                    <p className="text-sm text-red-700 mt-1 font-medium">{error}</p>
                  </div>
                </div>
              )}
              <InputForm
                formState={formState}
                setFormState={setFormState}
                onSubmit={handleSubmit}
                isLoading={false}
              />
            </div>

            <div className="lg:col-span-5 space-y-6">
              <div className="p-8 rounded-3xl bg-slate-900 text-white shadow-2xl shadow-indigo-100 overflow-hidden relative group">
