import { GoogleGenAI } from "@google/genai";
import { ResearchResult } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const generateResearchProfile = async (
  name: string,
  url: string,
  goal: string
): Promise<ResearchResult> => {
  const prompt = `
You are an Evidence-Based Research Analyst specializing in professional relationship intelligence.

TARGET: ${name}
CONTEXT URL: ${url || "Search based on name and professional context"}
RESEARCH GOAL: ${goal}

### CRITICAL CONSTRAINTS (DO NOT VIOLATE):
1. **NO PSEUDO-PSYCHOLOGY**: Never derive personality traits from technical metadata. For example, do NOT suggest a person is "pragmatic" or "low-ego" because they haven't customized their LinkedIn URL (e.g., "b68539126"). This is illogical and prohibited.
2. **FACTUAL GROUNDING ONLY**: Every insight must be tied to a specific piece of public evidence (news, LinkedIn posts, company bio, or project history).
3. **GRACEFUL FAILURE**: If you cannot find sufficient public information for a section, write: "Insufficient public data available for this section." Do NOT fabricate details.
4. **NO HALLUCINATIONS**: If the target's identity is ambiguous, focus only on the most likely professional match and add a disclaimer.
5. **PLAIN LANGUAGE**: Use professional, objective language. Avoid "marketing speak" or corporate buzzwords.

### MANDATORY OUTPUT STRUCTURE (Markdown):

# Insight Profile: ${name}

## Executive Summary
**Strategic Context:** (How this specific individual's current professional role or trajectory aligns with the goal: "${goal}")
**Objective Summary:** (A factual, 2-sentence summary of their professional standing.)

## 1. Verified Digital Activity
(List 3 specific, recent actions, news mentions, or verified career milestones. Explain the relevance to the user's goal.)

## 2. Professional Style & Expertise
(Group evidence into 2-3 objective categories. Use names like "Technical Leadership" or "Strategic Advisory" based on their actual history.)

### Area: [Objective Category Name]
* **The Evidence:** [Directly cite a project, post, or role]
* **Observed Approach:** [How they handled this, based strictly on the data]
* **Impact for You:** [How this specific expert area affects your meeting goal]

## 3. Communication Strategy (Evidence-Based)
*   **Optimal Approach:** (Based on their public writing style or speaking engagements—Direct? Detail-oriented? Academic?)
*   **Focus Areas:** (Topics they frequently discuss publicly)
*   **Friction Points:** (Behavioral patterns to avoid, derived from their public career path or stated preferences)

## 4. Final Recommendation
A single, objective piece of advice for a successful interaction with ${name} based on the research.
`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
        thinkingConfig: { thinkingBudget: 4000 }
      },
    });

    const markdownContent = response.text || "Analysis could not be generated.";
    const sources: { uri: string; title: string }[] = [];
    const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;

    if (chunks) {
      chunks.forEach((chunk: any) => {
        if (chunk.web) {
          sources.push({ uri: chunk.web.uri, title: chunk.web.title });
        }
      });
    }

    return { markdownContent, sources };
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw new Error("The search took too long or failed. Please refine the name or URL and try again.");
  }
};

